   for more details.

   You should have received a copy of the GNU General Public License
   along with GCC; see the file COPYING3.  If not see
   <http://www.gnu.org/licenses/>.  */

#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "tree-pass.h"
#include "cfg.h"
#include "basic-block.h"

namespace {

const pass_data pass_data_count_blocks =
{
  GIMPLE_PASS, /* type */
  "count-blocks", /* name */
  OPTGROUP_NONE, /* optinfo_flags */
  TV_NONE, /* tv_id */
  PROP_cfg, /* properties_required */
  0, /* properties_provided */
  0, /* properties_destroyed */
  0, /* todo_flags_start */
  0, /* todo_flags_finish */
};

class pass_count_blocks : public gimple_opt_pass
{
public:
  pass_count_blocks (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_count_blocks, ctxt)
  {}

  /* opt_pass methods: */
  opt_pass * clone () final override { return new pass_count_blocks (m_ctxt); }
  bool gate (function *) final override { return true; }
  unsigned int execute (function *) final override;

}; // class pass_count_blocks

unsigned int
pass_count_blocks::execute (function *fun)
{
  /* Count the number of basic blocks in the function. */
  int block_count = n_basic_blocks_for_fn (fun);

  if (dump_file)
    {
      fprintf (dump_file, "Function: %s\n", function_name (fun));
      fprintf (dump_file, "Basic block count: %d\n", block_count);

      /* Optionally iterate through each basic block and count statements */
      int stmt_count = 0;
      basic_block bb;
      FOR_EACH_BB_FN (bb, fun)
        {
          for (gimple_stmt_iterator gsi = gsi_start_bb (bb); !gsi_end_p (gsi);
               gsi_next (&gsi))
            {
              stmt_count++;
            }
        }
      fprintf (dump_file, "Total statement count: %d\n\n", stmt_count);
    }

  return 0;
}

} // anon namespace

gimple_opt_pass *
make_pass_count_blocks (gcc::context *ctxt)
{
  return new pass_count_blocks (ctxt);
}

